+const std = @import("std");
+const context_pool = @import("context_pool.zig");
+const memory_monitor = @import("memory_monitor.zig");
+const usage_profiler = @import("usage_profiler.zig");
+
+const ContextPool = context_pool.ContextPool;
+const PooledContext = context_pool.PooledContext;
+const MemoryMonitor = memory_monitor.MemoryMonitor;
+const UsageProfiler = usage_profiler.UsageProfiler;
+
+/// Context hint from user
+pub const ContextHint = enum {
+    short, // Use tier 0-1 (512-1024)
+    medium, // Use tier 1-2 (1024-2048)
+    long, // Use tier 2-3 (2048-4096)
+    auto, // Let system decide
+
+    pub fn fromString(s: []const u8) ?ContextHint {
+        if (std.mem.eql(u8, s, "short")) return .short;
+        if (std.mem.eql(u8, s, "medium")) return .medium;
+        if (std.mem.eql(u8, s, "long")) return .long;
+        if (std.mem.eql(u8, s, "auto")) return .auto;
+        return null;
+    }
+
+    pub fn toString(self: ContextHint) []const u8 {
+        return switch (self) {
+            .short => "short",
+            .medium => "medium",
+            .long => "long",
+            .auto => "auto",
+        };
+    }
+
+    fn toMaxTier(self: ContextHint) usize {
+        return switch (self) {
+            .short => 1, // Max 1024
+            .medium => 2, // Max 2048
+            .long => 3, // Max 4096
+            .auto => 3, // Let system decide up to max
+        };
+    }
+};
+
+/// Request information for tier selection
+pub const RequestInfo = struct {
+    prompt_tokens: usize,
+    max_tokens: usize,
+    complexity_hint: ?ContextHint,
+    historical_pattern: ?u64, // Hash of similar prompts
+
+    pub fn init(prompt: []const u8, max_tokens: usize, hint: ?ContextHint) RequestInfo {
+        return RequestInfo{
+            .prompt_tokens = estimateTokenCount(prompt),
+            .max_tokens = max_tokens,
+            .complexity_hint = hint,
+            .historical_pattern = if (prompt.len > 0)
+                std.hash.Wyhash.hash(0, prompt)
+            else
+                null,
+        };
+    }
+};
+
+/// Adaptive budget manager - central coordinator
+pub const AdaptiveBudgetManager = struct {
+    allocator: std.mem.Allocator,
+    context_pool: *ContextPool,
+    memory_monitor: *MemoryMonitor,
+    profiler: *UsageProfiler,
+
+    // Configuration
+    token_threshold: f32, // Grow at 80% capacity
+    enable_profiling: bool,
+    enable_hints: bool,
+    enable_memory_monitoring: bool,
+
+    pub fn init(
+        allocator: std.mem.Allocator,
+        pool: *ContextPool,
+        monitor: *MemoryMonitor,
+        prof: *UsageProfiler,
+    ) !AdaptiveBudgetManager {
+        return AdaptiveBudgetManager{
+            .allocator = allocator,
+            .context_pool = pool,
+            .memory_monitor = monitor,
+            .profiler = prof,
+            .token_threshold = 0.80, // Grow when 80% full
+            .enable_profiling = true,
+            .enable_hints = true,
+            .enable_memory_monitoring = true,
+        };
+    }
+
+    pub fn deinit(self: *AdaptiveBudgetManager) void {
+        _ = self;
+        // No cleanup needed currently
+    }
+
+    /// Select optimal tier for a request
+    pub fn selectOptimalTier(
+        self: *AdaptiveBudgetManager,
+        request: RequestInfo,
+    ) !usize {
+        // 1. Check memory pressure
+        var max_tier: usize = 3; // Default: allow up to 4096
+
+        if (self.enable_memory_monitoring) {
+            const pressure = try self.memory_monitor.getCurrentPressure();
+            max_tier = switch (pressure) {
+                .low => 3, // Can use up to 4096
+                .medium => 2, // Max 2048
+                .high => 1, // Max 1024
+                .critical => 0, // Force 512
+            };
+
+            if (pressure == .high or pressure == .critical) {
+                std.debug.print(
+                    "⚠ Memory pressure: {s}, limiting context to tier {}\n",
+                    .{ pressure.toString(), max_tier },
+                );
+            }
+        }
+
+        // 2. Apply user hint if provided
+        if (self.enable_hints) {
+            if (request.complexity_hint) |hint| {
+                if (hint != .auto) {
+                    const hint_tier = hint.toMaxTier();
+                    max_tier = @min(max_tier, hint_tier);
+                    std.debug.print(
+                        "ℹ User hint: {s}, max tier: {}\n",
+                        .{ hint.toString(), max_tier },
+                    );
+                }
+            }
+        }
+
+        // 3. Check profiling history
+        if (self.enable_profiling) {
+            if (request.historical_pattern) |pattern| {
+                if (try self.profiler.getPredictedTier(pattern)) |predicted| {
+                    const profiled_tier = @min(predicted, max_tier);
+                    std.debug.print(
+                        "📊 Profiler suggests tier {} based on history\n",
+                        .{profiled_tier},
+                    );
+                    return profiled_tier;
+                }
+            }
+        }
+
+        // 4. Calculate based on estimated token count
+        const estimated_tokens = request.prompt_tokens + request.max_tokens;
+        const required_tier = tokensToTier(estimated_tokens);
+
+        const selected_tier = @min(required_tier, max_tier);
+
+        std.debug.print(
+            "🎯 Selected tier {} ({} tokens) for estimated {} tokens\n",
+            .{ selected_tier, context_pool.TIER_SIZES[selected_tier], estimated_tokens },
+        );
+
+        return selected_tier;
+    }
+
+    /// Check if context should resize and perform migration if needed
+    pub fn checkAndResize(
+        self: *AdaptiveBudgetManager,
+        current_ctx: *PooledContext,
+        current_tokens: usize,
+    ) !?*PooledContext {
+        // Check if approaching threshold
+        const usage_pct = @as(f32, @floatFromInt(current_tokens)) /
+            @as(f32, @floatFromInt(current_ctx.n_ctx));
+
+        if (usage_pct < self.token_threshold) {
+            return null; // No resize needed
+        }
+
+        std.debug.print(
+            "⚡ Context usage at {d:.1}%, considering resize...\n",
+            .{usage_pct * 100.0},
+        );
+
+        // Try to grow to next tier
+        const next_tier = current_ctx.tier + 1;
+        if (next_tier >= 4) {
+            std.debug.print("⚠ Already at maximum tier, cannot grow\n", .{});
+            return null;
+        }
+
+        // Check memory pressure
+        if (self.enable_memory_monitoring) {
+            const pressure = try self.memory_monitor.getCurrentPressure();
+
+            if (pressure == .high or pressure == .critical) {
+                std.debug.print(
+                    "⚠ Cannot grow: memory pressure is {s}\n",
+                    .{pressure.toString()},
+                );
+                return null;
+            }
+
+            // Estimate memory growth
+            const current_size_gb = tierToMemoryGb(current_ctx.tier);
+            const next_size_gb = tierToMemoryGb(next_tier);
+            const growth_gb = next_size_gb - current_size_gb;
+
+            if (!try self.memory_monitor.canGrowContext(growth_gb)) {
+                std.debug.print(
+                    "⚠ Cannot grow: insufficient memory headroom ({d:.2}GB needed)\n",
+                    .{growth_gb},
+                );
+                return null;
+            }
+        }
+
+        // Attempt to acquire larger context
+        std.debug.print("↗ Growing context from tier {} to tier {}...\n", .{ current_ctx.tier, next_tier });
+
+        const new_ctx = self.context_pool.acquire(next_tier) catch |err| {
+            std.debug.print("⚠ Failed to acquire tier {}: {}\n", .{ next_tier, err });
+            return null;
+        };
+
+        // Migrate KV cache
+        self.context_pool.migrate(current_ctx, new_ctx) catch |err| {
+            std.debug.print("⚠ KV cache migration failed: {}\n", .{err});
+            // Release new context and return original
+            self.context_pool.release(new_ctx);
+            return null;
+        };
+
+        std.debug.print(
+            "✓ Context grown: {} -> {} tokens\n",
+            .{ current_ctx.n_ctx, new_ctx.n_ctx },
+        );
+
+        // Release old context
+        self.context_pool.release(current_ctx);
+
+        return new_ctx;
+    }
+
+    /// Check if context should shrink due to memory pressure
+    pub fn checkShrink(
+        self: *AdaptiveBudgetManager,
+        current_ctx: *PooledContext,
+        current_tokens: usize,
+    ) !?*PooledContext {
+        _ = current_tokens;
+
+        if (!self.enable_memory_monitoring) {
+            return null;
+        }
+
+        if (!try self.memory_monitor.shouldShrinkContext()) {
+            return null;
+        }
+
+        // Try to shrink to lower tier
+        const prev_tier = if (current_ctx.tier > 0) current_ctx.tier - 1 else 0;
+        if (prev_tier == current_ctx.tier) {
+            return null; // Already at minimum
+        }
+
+        std.debug.print(
+            "↘ Memory pressure detected, shrinking context from tier {} to tier {}...\n",
+            .{ current_ctx.tier, prev_tier },
+        );
+
+        const new_ctx = self.context_pool.acquire(prev_tier) catch |err| {
+            std.debug.print("⚠ Failed to acquire tier {}: {}\n", .{ prev_tier, err });
+            return null;
+        };
+
+        // Migrate KV cache (may lose tokens if they don't fit)
+        self.context_pool.migrate(current_ctx, new_ctx) catch |err| {
+            std.debug.print("⚠ KV cache migration failed: {}\n", .{err});
+            self.context_pool.release(new_ctx);
+            return null;
+        };
+
+        std.debug.print(
+            "✓ Context shrunk: {} -> {} tokens\n",
+            .{ current_ctx.n_ctx, new_ctx.n_ctx },
+        );
+
+        self.context_pool.release(current_ctx);
+        return new_ctx;
+    }
+
+    /// Record usage pattern for future predictions
+    pub fn recordUsage(
+        self: *AdaptiveBudgetManager,
+        prompt: []const u8,
+        tokens_used: usize,
+        tier_used: usize,
+        success: bool,
+    ) !void {
+        if (self.enable_profiling) {
+            try self.profiler.recordUsage(prompt, tokens_used, tier_used, success);
+        }
+    }
+};
+
+// Helper functions
+
+/// Estimate token count from text (rough approximation)
+fn estimateTokenCount(text: []const u8) usize {
+    // Rough estimate: ~4 characters per token
+    // This is conservative and will tend to overestimate
+    return (text.len + 3) / 4;
+}
+
+/// Convert estimated token count to required tier
+fn tokensToTier(tokens: usize) usize {
+    if (tokens <= 512) return 0;
+    if (tokens <= 1024) return 1;
+    if (tokens <= 2048) return 2;
+    return 3;
+}
+
+/// Estimate memory usage for a tier (GB)
+fn tierToMemoryGb(tier: usize) f64 {
+    // Rough estimates for fp16 KV cache with 32 layers, 4096 embd
+    const estimates = [_]f64{
+        0.5, // Tier 0: 512 tokens
+        1.0, // Tier 1: 1024 tokens
+        2.0, // Tier 2: 2048 tokens
+        4.0, // Tier 3: 4096 tokens
+    };
+    return if (tier < estimates.len) estimates[tier] else 4.0;
+}
+
+// Tests
+test "context hint parsing" {
+    try std.testing.expect(ContextHint.fromString("short") == .short);
+    try std.testing.expect(ContextHint.fromString("long") == .long);
+    try std.testing.expect(ContextHint.fromString("invalid") == null);
+}
+
+test "tokens to tier conversion" {
+    try std.testing.expectEqual(@as(usize, 0), tokensToTier(400));
+    try std.testing.expectEqual(@as(usize, 1), tokensToTier(800));
+    try std.testing.expectEqual(@as(usize, 2), tokensToTier(1500));
+    try std.testing.expectEqual(@as(usize, 3), tokensToTier(3000));
+}
+
+test "token estimation" {
+    const text = "Hello world this is a test";
+    const estimated = estimateTokenCount(text);
+    // ~26 chars / 4 = ~6.5 tokens, rounds up to 7
+    try std.testing.expect(estimated >= 6 and estimated <= 8);
+}
+
+test "request info init" {
+    const request = RequestInfo.init("Test prompt", 100, .auto);
+    try std.testing.expect(request.max_tokens == 100);
+    try std.testing.expect(request.complexity_hint == .auto);
+    try std.testing.expect(request.historical_pattern != null);
+}

