+const std = @import("std");
+
+/// Usage pattern for a specific prompt or prompt family
+pub const UsagePattern = struct {
+    prompt_hash: u64,
+    prompt_tokens: usize,
+    max_tokens_generated: usize,
+    optimal_tier: usize,
+    success_count: usize,
+    failure_count: usize,
+    last_used: i64,
+
+    pub fn successRate(self: UsagePattern) f64 {
+        const total = self.success_count + self.failure_count;
+        if (total == 0) return 0.0;
+        return @as(f64, @floatFromInt(self.success_count)) /
+            @as(f64, @floatFromInt(total));
+    }
+
+    pub fn isReliable(self: UsagePattern) bool {
+        // Consider pattern reliable if success rate > 80% and at least 3 uses
+        return self.successRate() >= 0.8 and
+            (self.success_count + self.failure_count) >= 3;
+    }
+};
+
+/// Usage profiler for learning optimal tiers
+pub const UsageProfiler = struct {
+    allocator: std.mem.Allocator,
+    history: std.AutoHashMap(u64, UsagePattern),
+    max_history: usize,
+    profile_file: ?[]const u8,
+
+    pub fn init(allocator: std.mem.Allocator) !UsageProfiler {
+        return UsageProfiler{
+            .allocator = allocator,
+            .history = std.AutoHashMap(u64, UsagePattern).init(allocator),
+            .max_history = 1000,
+            .profile_file = null,
+        };
+    }
+
+    pub fn initWithFile(allocator: std.mem.Allocator, profile_path: []const u8) !UsageProfiler {
+        var profiler = try init(allocator);
+        profiler.profile_file = profile_path;
+
+        // Try to load existing profile
+        profiler.load() catch |err| {
+            std.debug.print(
+                "Note: Could not load usage profile: {} (starting fresh)\n",
+                .{err},
+            );
+        };
+
+        return profiler;
+    }
+
+    pub fn deinit(self: *UsageProfiler) void {
+        // Try to save profile before cleanup
+        if (self.profile_file) |_| {
+            self.save() catch |err| {
+                std.debug.print("Warning: Failed to save usage profile: {}\n", .{err});
+            };
+        }
+
+        self.history.deinit();
+    }
+
+    /// Record usage of a prompt with a specific tier
+    pub fn recordUsage(
+        self: *UsageProfiler,
+        prompt: []const u8,
+        tokens_used: usize,
+        tier_used: usize,
+        success: bool,
+    ) !void {
+        const hash = std.hash.Wyhash.hash(0, prompt);
+
+        if (self.history.get(hash)) |pattern| {
+            // Update existing pattern
+            var updated = pattern;
+            updated.max_tokens_generated = @max(
+                updated.max_tokens_generated,
+                tokens_used,
+            );
+            updated.last_used = std.time.timestamp();
+
+            if (success) {
+                updated.success_count += 1;
+                // Update optimal tier if this was successful
+                updated.optimal_tier = tier_used;
+            } else {
+                updated.failure_count += 1;
+            }
+
+            try self.history.put(hash, updated);
+        } else {
+            // New pattern
+            try self.history.put(hash, UsagePattern{
+                .prompt_hash = hash,
+                .prompt_tokens = estimateTokenCount(prompt),
+                .max_tokens_generated = tokens_used,
+                .optimal_tier = tier_used,
+                .success_count = if (success) 1 else 0,
+                .failure_count = if (!success) 1 else 0,
+                .last_used = std.time.timestamp(),
+            });
+        }
+
+        // Enforce max history size
+        if (self.history.count() > self.max_history) {
+            try self.pruneOldest();
+        }
+    }
+
+    /// Get predicted tier for a prompt pattern
+    pub fn getPredictedTier(
+        self: *UsageProfiler,
+        pattern_hash: u64,
+    ) !?usize {
+        if (self.history.get(pattern_hash)) |pattern| {
+            // Only use prediction if pattern is reliable
+            if (pattern.isReliable()) {
+                return pattern.optimal_tier;
+            }
+        }
+        return null;
+    }
+
+    /// Get statistics about the profiler
+    pub fn getStats(self: *UsageProfiler) ProfilerStats {
+        var stats = ProfilerStats{
+            .total_patterns = self.history.count(),
+            .reliable_patterns = 0,
+            .tier_distribution = [_]usize{0} ** 4,
+        };
+
+        var iter = self.history.valueIterator();
+        while (iter.next()) |pattern| {
+            if (pattern.isReliable()) {
+                stats.reliable_patterns += 1;
+                if (pattern.optimal_tier < 4) {
+                    stats.tier_distribution[pattern.optimal_tier] += 1;
+                }
+            }
+        }
+
+        return stats;
+    }
+
+    /// Clear all history
+    pub fn clear(self: *UsageProfiler) !void {
+        self.history.clearRetainingCapacity();
+    }
+
+    /// Save profile to disk
+    pub fn save(self: *UsageProfiler) !void {
+        const path = self.profile_file orelse return error.NoProfileFile;
+
+        const file = try std.fs.cwd().createFile(path, .{});
+        defer file.close();
+
+        var writer = file.writer();
+
+        // Write header
+        try writer.writeAll("# Zell Usage Profile v1\n");
+        try writer.print("# Total patterns: {}\n\n", .{self.history.count()});
+
+        // Write patterns
+        var iter = self.history.iterator();
+        while (iter.next()) |entry| {
+            const pattern = entry.value_ptr.*;
+            try writer.print(
+                "{x:0>16},{},{},{},{},{},{}\n",
+                .{
+                    pattern.prompt_hash,
+                    pattern.prompt_tokens,
+                    pattern.max_tokens_generated,
+                    pattern.optimal_tier,
+                    pattern.success_count,
+                    pattern.failure_count,
+                    pattern.last_used,
+                },
+            );
+        }
+    }
+
+    /// Load profile from disk
+    pub fn load(self: *UsageProfiler) !void {
+        const path = self.profile_file orelse return error.NoProfileFile;
+
+        const file = try std.fs.cwd().openFile(path, .{});
+        defer file.close();
+
+        var buf_reader = std.io.bufferedReader(file.reader());
+        var reader = buf_reader.reader();
+
+        var line_buf: [512]u8 = undefined;
+        while (try reader.readUntilDelimiterOrEof(&line_buf, '\n')) |line| {
+            // Skip comments
+            if (line.len == 0 or line[0] == '#') continue;
+
+            // Parse line: hash,prompt_tokens,max_tokens,tier,success,failure,last_used
+            var parts = std.mem.split(u8, line, ",");
+
+            const hash_str = parts.next() orelse continue;
+            const prompt_tokens_str = parts.next() orelse continue;
+            const max_tokens_str = parts.next() orelse continue;
+            const tier_str = parts.next() orelse continue;
+            const success_str = parts.next() orelse continue;
+            const failure_str = parts.next() orelse continue;
+            const last_used_str = parts.next() orelse continue;
+
+            const pattern = UsagePattern{
+                .prompt_hash = try std.fmt.parseInt(u64, hash_str, 16),
+                .prompt_tokens = try std.fmt.parseInt(usize, prompt_tokens_str, 10),
+                .max_tokens_generated = try std.fmt.parseInt(usize, max_tokens_str, 10),
+                .optimal_tier = try std.fmt.parseInt(usize, tier_str, 10),
+                .success_count = try std.fmt.parseInt(usize, success_str, 10),
+                .failure_count = try std.fmt.parseInt(usize, failure_str, 10),
+                .last_used = try std.fmt.parseInt(i64, last_used_str, 10),
+            };
+
+            try self.history.put(pattern.prompt_hash, pattern);
+        }
+    }
+
+    /// Remove oldest patterns when max history is exceeded
+    fn pruneOldest(self: *UsageProfiler) !void {
+        // Find oldest pattern
+        var oldest_hash: ?u64 = null;
+        var oldest_time: i64 = std.math.maxInt(i64);
+
+        var iter = self.history.iterator();
+        while (iter.next()) |entry| {
+            if (entry.value_ptr.last_used < oldest_time) {
+                oldest_time = entry.value_ptr.last_used;
+                oldest_hash = entry.key_ptr.*;
+            }
+        }
+
+        // Remove oldest
+        if (oldest_hash) |hash| {
+            _ = self.history.remove(hash);
+        }
+    }
+};
+
+pub const ProfilerStats = struct {
+    total_patterns: usize,
+    reliable_patterns: usize,
+    tier_distribution: [4]usize,
+
+    pub fn format(
+        self: ProfilerStats,
+        comptime fmt: []const u8,
+        options: std.fmt.FormatOptions,
+        writer: anytype,
+    ) !void {
+        _ = fmt;
+        _ = options;
+        try writer.print(
+            "ProfilerStats{{ total={}, reliable={}, tiers=[{},{},{},{}] }}",
+            .{
+                self.total_patterns,
+                self.reliable_patterns,
+                self.tier_distribution[0],
+                self.tier_distribution[1],
+                self.tier_distribution[2],
+                self.tier_distribution[3],
+            },
+        );
+    }
+};
+
+// Helper functions
+
+fn estimateTokenCount(text: []const u8) usize {
+    // Rough estimate: ~4 characters per token
+    return (text.len + 3) / 4;
+}
+
+// Tests
+test "usage pattern success rate" {
+    const pattern = UsagePattern{
+        .prompt_hash = 123,
+        .prompt_tokens = 10,
+        .max_tokens_generated = 100,
+        .optimal_tier = 1,
+        .success_count = 8,
+        .failure_count = 2,
+        .last_used = 0,
+    };
+
+    try std.testing.expectEqual(@as(f64, 0.8), pattern.successRate());
+    try std.testing.expect(pattern.isReliable());
+}
+
+test "usage profiler init" {
+    const allocator = std.testing.allocator;
+
+    var profiler = try UsageProfiler.init(allocator);
+    defer profiler.deinit();
+
+    try std.testing.expectEqual(@as(usize, 0), profiler.history.count());
+    try std.testing.expectEqual(@as(usize, 1000), profiler.max_history);
+}
+
+test "usage profiler record and predict" {
+    const allocator = std.testing.allocator;
+
+    var profiler = try UsageProfiler.init(allocator);
+    defer profiler.deinit();
+
+    const prompt = "Test prompt";
+
+    // Record successful uses
+    try profiler.recordUsage(prompt, 50, 1, true);
+    try profiler.recordUsage(prompt, 60, 1, true);
+    try profiler.recordUsage(prompt, 55, 1, true);
+
+    // Should predict tier 1
+    const hash = std.hash.Wyhash.hash(0, prompt);
+    const predicted = try profiler.getPredictedTier(hash);
+
+    try std.testing.expect(predicted != null);
+    try std.testing.expectEqual(@as(usize, 1), predicted.?);
+}
